from prometheus_flask_exporter import CollectorRegistry, generate_default_config, start_web_server
from prometheus_client import Counter, Histogram, Gauge
from flask import Flask, request

app = Flask(__name__)
registry = CollectorRegistry()

# Create a counter for each unique user-path combination
